        $nationality = $nationality ?? '';
        $timeout = (int)($timeout ?? 15);

        if ($count < 1) $count = 1;
        if ($count > 20) $count = 20;

        // RandomUser.me — free, no key
        $url = 'https://randomuser.me/api/?results=' . $count;
        if (!empty($gender) && in_array($gender, ['male', 'female'])) {
